   310→      {/* Advanced Filters (Issue #37) */}
   311→      <div className="flex flex-wrap items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-lg border border-slate-200 dark:border-slate-700">
   312→        <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400">
   313→          <Filter className="w-4 h-4" />
   314→          <span className="font-medium">Filtri:</span>
   315→        </div>
   316→
   317→        {/* Subject Filter */}
   318→        <div className="relative">
   319→          <select
   320→            value={subjectFilter}
   321→            onChange={(e) => setSubjectFilter(e.target.value)}
   322→            className="appearance-none pl-8 pr-8 h-8 rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm focus:outline-none focus:ring-2 focus:ring-primary cursor-pointer"
   323→            aria-label="Filtra per materia"
   324→          >
   325→            <option value="all">Tutte le materie</option>
   326→            {availableSubjects.map((subject) => (
   327→              <option key={subject} value={subject}>
   328→                {SUBJECT_LABELS[subject] || subject}
   329→              </option>
   330→            ))}
   331→          </select>
   332→          <BookOpen className="absolute left-2.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
   333→        </div>
   334→
   335→        {/* Date Range Filter */}
   336→        <div className="flex items-center gap-2">
   337→          <div className="relative">
   338→            <input
   339→              type="date"
   340→              value={dateFrom}
   341→              onChange={(e) => setDateFrom(e.target.value)}
   342→              className="pl-8 pr-3 h-8 rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
   343→              aria-label="Data da"
   344→            />
   345→            <Calendar className="absolute left-2.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
   346→          </div>
   347→          <span className="text-slate-400">-</span>
   348→          <div className="relative">
   349→            <input
   350→              type="date"
   351→              value={dateTo}
   352→              onChange={(e) => setDateTo(e.target.value)}
   353→              className="pl-8 pr-3 h-8 rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
   354→              aria-label="Data a"
   355→            />
   356→            <Calendar className="absolute left-2.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
   357→          </div>
   358→        </div>
   359→
   360→        {/* Clear Filters Button */}
   361→        {(subjectFilter !== 'all' || dateFrom || dateTo) && (
   362→          <Button
   363→            variant="ghost"
   364→            size="sm"
   365→            onClick={() => {
   366→              setSubjectFilter('all');
   367→              setDateFrom('');
   368→              setDateTo('');
   369→            }}
   370→            className="text-xs gap-1"
   371→          >
   372→            <X className="w-3 h-3" />
   373→            Pulisci filtri
   374→          </Button>
   375→        )}
   376→      </div>
   377→
   378→      {/* Content */}
   379→      <div role="tabpanel" aria-label={`Materiali ${filter === 'all' ? 'tutti' : filter === 'bookmarked' ? 'preferiti' : TOOL_LABELS[filter]}`}>
   380→        {isLoading ? (
   381→          <div className="flex items-center justify-center py-16">
   382→            <div className="animate-spin w-8 h-8 border-2 border-primary border-t-transparent rounded-full" />
   383→          </div>
   384→        ) : filtered.length === 0 ? (
   385→          <EmptyState filter={filter} />
   386→        ) : viewMode === 'grid' ? (
   387→          <GridView
   388→            items={filtered}
   389→            onDelete={handleDelete}
   390→            onView={handleView}
   391→            onBookmark={handleBookmark}
   392→            onRate={handleRate}
   393→          />
   394→        ) : (
   395→          <ListView
   396→            items={filtered}
   397→            onDelete={handleDelete}
   398→            onView={handleView}
   399→            onBookmark={handleBookmark}
   400→            onRate={handleRate}
   401→          />
   402→        )}
   403→      </div>
   404→
   405→      {/* Material Viewer Modal */}
   406→      <AnimatePresence>
   407→        {selectedItem && (
   408→          <MaterialViewer item={selectedItem} onClose={handleCloseViewer} />
   409→        )}
   410→      </AnimatePresence>
   411→    </div>
   412→  );
   413→}
