// ============================================================================
// CONVERGIO WEB - TYPE DEFINITIONS
// Migrated from ConvergioApp native macOS application
// ============================================================================

// === MAESTRO TYPES ===

export type MaestroVoice =
  | 'alloy'
  | 'ash'
  | 'ballad'
  | 'coral'
  | 'echo'
  | 'sage'
  | 'shimmer'
  | 'verse';

export type Subject =
  | 'mathematics'
  | 'physics'
  | 'chemistry'
  | 'biology'
  | 'history'
  | 'geography'
  | 'italian'
  | 'english'
  | 'art'
  | 'music'
  | 'civics'
  | 'economics'
  | 'computerScience'
  | 'health'
  | 'philosophy'
  | 'internationalLaw';

export interface Maestro {
  id: string;
  name: string;
  subject: Subject;
  specialty: string;
  voice: MaestroVoice;
  voiceInstructions: string;  // How to speak/personality for voice
  teachingStyle: string;
  avatar: string;
  color: string;
  systemPrompt: string;
  greeting: string;
}

// === VOICE SESSION TYPES ===

export type VoiceSessionState =
  | 'idle'
  | 'connecting'
  | 'connected'
  | 'listening'
  | 'processing'
  | 'speaking'
  | 'error';

export type VoiceConnectionState = 'idle' | 'connecting' | 'connected' | 'error';

/**
 * Handle returned by useVoiceSession hook.
 * Used to pass voice session state between components without re-creating connections.
 */
export interface VoiceSessionHandle {
  isConnected: boolean;
  isListening: boolean;
  isSpeaking: boolean;
  isMuted: boolean;
  connectionState: VoiceConnectionState;
  connect: (maestro: Maestro, connectionInfo: { provider: 'azure'; proxyPort?: number }) => Promise<void>;
  disconnect: () => void;
  toggleMute: () => void;
}

export type EmotionType =
  | 'neutral'
  | 'joy'
  | 'excitement'
  | 'curiosity'
  | 'confusion'
  | 'frustration'
  | 'anxiety'
  | 'boredom'
  | 'distraction';

export interface Emotion {
  type: EmotionType;
  confidence: number;
  color: string;
}

export interface TranscriptEntry {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  emotion?: Emotion;
}

export interface AudioLevels {
  input: number;
  output: number;
}

// === EDUCATION TYPES ===

export type QuestionType = 'multiple_choice' | 'true_false' | 'open_ended';

export interface Question {
  id: string;
  text: string;
  type: QuestionType;
  options?: string[];
  correctAnswer: string | number;
  hints: string[];
  explanation: string;
  difficulty: 1 | 2 | 3 | 4 | 5;
  subject: Subject;
  topic: string;
}

export interface Quiz {
  id: string;
  title: string;
  subject: Subject;
  questions: Question[];
  timeLimit?: number; // seconds
  masteryThreshold: number; // 0-100
  xpReward: number;
}

export interface QuizResult {
  quizId: string;
  score: number;
  totalQuestions: number;
  correctAnswers: number;
  timeSpent: number;
  masteryAchieved: boolean;
  xpEarned: number;
  completedAt: Date;
}

// === FLASHCARD TYPES (FSRS-5) ===

export type CardState = 'new' | 'learning' | 'review' | 'relearning';
export type Rating = 'again' | 'hard' | 'good' | 'easy';

export interface Flashcard {
  id: string;
  deckId: string;
  front: string;
  back: string;
  state: CardState;
  stability: number;
  difficulty: number;
  elapsedDays: number;
  scheduledDays: number;
  reps: number;
  lapses: number;
  lastReview?: Date;
  nextReview: Date;
}

export interface FlashcardDeck {
  id: string;
  name: string;
  subject: Subject;
  cards: Flashcard[];
  createdAt: Date;
  lastStudied?: Date;
}

// === HOMEWORK TYPES ===

export interface HomeworkStep {
  id: string;
  description: string;
  hints: string[]; // 3 progressive hints
  studentNotes: string;
  completed: boolean;
}

export interface Homework {
  id: string;
  title: string;
  subject: Subject;
  problemType: string;
  steps: HomeworkStep[];
  photoUrl?: string;
  createdAt: Date;
  completedAt?: Date;
}

// === GAMIFICATION TYPES ===

export type MasteryTier =
  | 'beginner'
  | 'intermediate'
  | 'advanced'
  | 'expert'
  | 'master';

export interface SubjectMastery {
  subject: Subject;
  percentage: number;
  tier: MasteryTier;
  topicsCompleted: number;
  totalTopics: number;
  lastStudied?: Date;
}

export interface Streak {
  current: number;
  longest: number;
  lastStudyDate?: Date;
}

export interface Achievement {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: 'study' | 'mastery' | 'streak' | 'social' | 'exploration' | 'xp';
  requirement: number;
  xpReward: number;
  unlockedAt?: Date;
}

export interface Progress {
  xp: number;
  level: number;
  xpToNextLevel: number;
  streak: Streak;
  masteries: SubjectMastery[];
  achievements: Achievement[];
  totalStudyMinutes: number;
  sessionsThisWeek: number;
  questionsAsked: number;
}

// === GRADE TYPES (Italian System) ===

export type GradeType =
  | 'quiz'
  | 'homework'
  | 'test'
  | 'participation'
  | 'project'
  | 'oral';

export interface Grade {
  id: string;
  value: number; // 1-10 Italian scale
  subject: Subject;
  type: GradeType;
  description: string;
  date: Date;
}

export interface SubjectGrades {
  subject: Subject;
  grades: Grade[];
  average: number;
  trend: 'improving' | 'stable' | 'declining';
}

// === STUDENT PROFILE TYPES ===

export type Curriculum =
  | 'liceoClassico'
  | 'liceoScientifico'
  | 'liceoLinguistico'
  | 'liceoArtistico'
  | 'liceoMusicale'
  | 'istitutoTecnico'
  | 'istitutoProfessionale'
  | 'scuolaMedia'
  | 'scuolaElementare';

export type SchoolLevel = 'elementare' | 'media' | 'superiore';

export interface StudentProfile {
  name: string;
  age: number;
  schoolYear: number;
  schoolLevel: SchoolLevel;
  curriculum?: Curriculum;
  // Accessibility
  fontSize: 'small' | 'medium' | 'large' | 'extra-large';
  highContrast: boolean;
  dyslexiaFont: boolean;
  voiceEnabled: boolean;
  simplifiedLanguage: boolean;
  adhdMode: boolean;
}

// === SETTINGS TYPES ===

export type Theme = 'light' | 'dark' | 'system';

export type AIProvider =
  | 'openai'
  | 'anthropic'
  | 'azure'
  | 'gemini'
  | 'openrouter'
  | 'perplexity'
  | 'grok'
  | 'ollama';

export interface Settings {
  theme: Theme;
  provider: AIProvider;
  model: string;
  budgetLimit: number;
  studentProfile: StudentProfile;
}

// === TOOL TYPES ===

export type ToolType =
  | 'run_code'
  | 'create_chart'
  | 'create_diagram'
  | 'create_visualization'
  | 'show_formula'
  | 'create_quiz'
  | 'create_flashcard'
  | 'create_mindmap'
  | 'create_summary'
  | 'create_demo';

export interface ToolCall {
  id: string;
  type: ToolType;
  name: string;
  arguments: Record<string, unknown>;
  status: 'pending' | 'running' | 'completed' | 'error';
  result?: ToolResult;
}

export interface ToolResult {
  success: boolean;
  output?: string;
  error?: string;
  data?: unknown;
  renderComponent?: string; // Component name to render
}

export interface CodeExecutionRequest {
  language: 'python' | 'javascript';
  code: string;
  timeout?: number;
}

export interface ChartRequest {
  type: 'line' | 'bar' | 'pie' | 'scatter' | 'area';
  title: string;
  data: {
    labels: string[];
    datasets: Array<{
      label: string;
      data: number[];
      color?: string;
    }>;
  };
}

export interface DiagramRequest {
  type: 'flowchart' | 'sequence' | 'class' | 'state' | 'er';
  code: string; // Mermaid syntax (mind maps use MarkMap via create_mindmap tool)
  title?: string;
}

export interface FormulaRequest {
  latex: string;
  description?: string;
}

export interface VisualizationRequest {
  type: 'physics' | 'math' | 'chemistry' | 'biology';
  name: string;
  params: Record<string, number | string>;
}

export interface QuizRequest {
  title: string;
  subject: Subject;
  questions: Array<{
    text: string;
    type: QuestionType;
    options?: string[];
    correctAnswer: string | number;
    hints: string[];
    explanation: string;
    difficulty: 1 | 2 | 3 | 4 | 5;
    topic: string;
  }>;
  masteryThreshold?: number;
  xpReward?: number;
}

export interface FlashcardDeckRequest {
  name: string;
  subject: Subject;
  cards: Array<{
    front: string;
    back: string;
  }>;
}

export interface MindmapRequest {
  title: string;
  nodes: Array<{
    id: string;
    label: string;
    children?: Array<{
      id: string;
      label: string;
      children?: Array<{
        id: string;
        label: string;
      }>;
    }>;
    icon?: string;
    color?: string;
  }>;
}

// === CHAT TYPES ===

export type ChatRole = 'system' | 'user' | 'assistant';

/**
 * Session evaluation data displayed inline in chat.
 * Generated when a Maestro session ends.
 */
export interface SessionEvaluation {
  score: number; // 1-10
  feedback: string; // Maestro's comment
  strengths: string[]; // Punti di forza
  areasToImprove: string[]; // Da migliorare
  sessionDuration: number; // minutes
  questionsAsked: number;
  xpEarned: number;
  savedToDiary: boolean; // If written to Learning table
}

export type ChatMessageType = 'text' | 'voice' | 'evaluation' | 'tool';

export interface ChatMessage {
  id: string;
  role: ChatRole;
  content: string;
  timestamp: Date;
  tokens?: number;
  cost?: number;
  /** Message type for special rendering */
  type?: ChatMessageType;
  /** Evaluation data when type is 'evaluation' */
  evaluation?: SessionEvaluation;
  /** Indicates this was from voice transcript */
  isVoice?: boolean;
}

export interface Conversation {
  id: string;
  title: string;
  messages: ChatMessage[];
  maestroId?: string;
  systemPrompt?: string;
  createdAt: Date;
  updatedAt: Date;
}

// === SUPPORT CHARACTER TYPES (MirrorBuddy v2.0) ===

/**
 * Learning differences that the platform supports.
 * Used for both student profiles and buddy matching.
 */
export type LearningDifference =
  | 'dyslexia'
  | 'dyscalculia'
  | 'dysgraphia'
  | 'adhd'
  | 'autism'
  | 'cerebralPalsy'
  | 'visualImpairment'
  | 'auditoryProcessing';

/**
 * Role of support characters in the Support Triangle.
 */
export type SupportRole = 'learning_coach' | 'peer_buddy';

/**
 * Gender option for support characters.
 * Students can choose their preferred coach/buddy gender.
 */
export type CharacterGender = 'male' | 'female';

/**
 * Extended student profile with learning differences.
 * Used by Mario/Noemi buddies to personalize their approach.
 */
export interface ExtendedStudentProfile extends StudentProfile {
  learningDifferences: LearningDifference[];
  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
}

/**
 * Support Teacher (Melissa/Roberto) - Learning Coach role.
 * Focus: develop autonomy and study method.
 * Relationship: vertical (coach), but talks "alongside" not "from above".
 */
export interface SupportTeacher {
  id: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
  name: string;
  gender: CharacterGender;
  age: number;
  personality: string;
  role: 'learning_coach';
  voice: MaestroVoice;
  voiceInstructions: string;
  systemPrompt: string;
  greeting: string;
  avatar: string;
  color: string;
}

/**
 * MirrorBuddy (Mario/Noemi) - Peer Support role.
 * Focus: make student feel less alone.
 * Relationship: horizontal (friend), speaks as peer.
 *
 * System prompt is dynamic based on student profile:
 * - Age is always student.age + 1
 * - Learning differences mirror the student's
 */
export interface BuddyProfile {
  id: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
  name: string;
  gender: CharacterGender;
  ageOffset: number; // Always 1 (one year older)
  personality: string;
  role: 'peer_buddy';
  voice: MaestroVoice;
  voiceInstructions: string;
  /**
   * Dynamic system prompt generator.
   * Takes student profile to personalize Mario/Maria's background.
   */
  getSystemPrompt: (student: ExtendedStudentProfile) => string;
  /**
   * Dynamic greeting generator.
   */
  getGreeting: (student: ExtendedStudentProfile) => string;
  avatar: string;
  color: string;
}

/**
 * Union type for any support character (coach or buddy).
 */
export type SupportCharacter = SupportTeacher | BuddyProfile;

/**
 * Character type identifier for routing.
 * Note: 'support_assistant' was removed in Issue #16 - coaches handle platform support directly.
 */
export type CharacterType = 'maestro' | 'coach' | 'buddy';

// === PARENT DASHBOARD TYPES ===

/**
 * Observation category for what each Maestro observes.
 * Maps to the Maestro's specialty and observation focus.
 */
export type ObservationCategory =
  | 'logical_reasoning'       // Archimede
  | 'creativity'              // Leonardo
  | 'verbal_expression'       // Dante
  | 'study_method'            // Montessori
  | 'critical_thinking'       // Socrate
  | 'artistic_sensitivity'    // Mozart
  | 'scientific_curiosity'    // Darwin
  | 'spatial_memory'          // Marco Polo
  | 'historical_understanding' // Giulio Cesare
  | 'mathematical_intuition'  // Pitagora
  | 'linguistic_ability'      // Cicerone
  | 'philosophical_depth'     // Aristotele
  | 'physical_awareness'      // Ippocrate
  | 'experimental_approach'   // Galileo
  | 'environmental_awareness' // Plinio
  | 'collaborative_spirit'    // Alessandro Magno
  | 'narrative_skill';        // Omero

/**
 * Single observation from a Maestro about the student.
 */
export interface MaestroObservation {
  id: string;
  maestroId: string;
  maestroName: string;
  category: ObservationCategory;
  observation: string;
  isStrength: boolean; // true = punto di forza, false = area di crescita
  confidence: number; // 0-1, how confident the Maestro is
  createdAt: Date;
  sessionId?: string;
}

/**
 * Suggested strategy for the student.
 */
export interface LearningStrategy {
  id: string;
  title: string;
  description: string;
  suggestedBy: string[]; // Maestro IDs that suggested this
  forAreas: ObservationCategory[];
  priority: 'high' | 'medium' | 'low';
}

/**
 * Learning style profile.
 */
export interface LearningStyleProfile {
  preferredChannel: 'visual' | 'auditory' | 'kinesthetic' | 'reading_writing';
  optimalSessionDuration: number; // minutes
  preferredTimeOfDay: 'morning' | 'afternoon' | 'evening';
  motivators: string[];
  challengePreference: 'step_by_step' | 'big_picture' | 'mixed';
}

/**
 * Complete student insights for parent dashboard.
 * Aggregated from all Maestro interactions.
 */
export interface StudentInsights {
  studentId: string;
  studentName: string;
  lastUpdated: Date;
  strengths: MaestroObservation[];
  growthAreas: MaestroObservation[];
  strategies: LearningStrategy[];
  learningStyle: LearningStyleProfile;
  totalSessions: number;
  totalMinutes: number;
  maestriInteracted: string[];
}

// === AMBIENT AUDIO TYPES ===

/**
 * Audio focus modes for procedural generation and ambient sounds.
 */
export type AudioMode =
  | 'white_noise'
  | 'pink_noise'
  | 'brown_noise'
  | 'binaural_alpha'    // 8-14 Hz - Relaxed focus
  | 'binaural_beta'     // 14-30 Hz - Active concentration
  | 'binaural_theta'    // 4-8 Hz - Creative, meditative
  | 'rain'
  | 'thunderstorm'
  | 'fireplace'
  | 'cafe'
  | 'library'
  | 'forest'
  | 'ocean'
  | 'night';

/**
 * Preset combinations of audio modes.
 */
export type AudioPreset =
  | 'deep_work'        // Binaural beta + brown noise
  | 'library'          // Quiet ambience + white noise
  | 'starbucks'        // Café + soft lo-fi
  | 'rainy_day'        // Rain + fireplace + thunder
  | 'nature'           // Forest + birds + wind
  | 'focus'            // Binaural alpha
  | 'creative';        // Binaural theta + nature

/**
 * Playback state of ambient audio system.
 */
export type AudioPlaybackState = 'idle' | 'playing' | 'paused' | 'loading' | 'error';

/**
 * Configuration for a single audio layer in the mixer.
 */
export interface AudioLayer {
  id: string;
  mode: AudioMode;
  volume: number;      // 0-1
  enabled: boolean;
}

/**
 * Ambient audio system state.
 */
export interface AmbientAudioState {
  playbackState: AudioPlaybackState;
  masterVolume: number;        // 0-1
  currentPreset: AudioPreset | null;
  layers: AudioLayer[];
  // Auto-ducking: reduce volume during voice/TTS
  autoDuckEnabled: boolean;
  duckedVolume: number;        // Volume to reduce to when ducking (0-1)
  // Integration with study sessions
  autoStartWithStudy: boolean;
  studySessionAudioMode: AudioMode | null;
  // Error state
  error: string | null;
}

// ============================================================================
// CONVERGIO WEB - DATABASE SCHEMA
// SQLite for local, PostgreSQL for cloud (same schema works for both)
// ============================================================================

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
}

// ============================================================================
// USER & PROFILE
// ============================================================================

model User {
  id        String   @id @default(cuid())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  profile       Profile?
  settings      Settings?
  progress      Progress?
  sessions          StudySession[]
  flashcards        FlashcardProgress[]
  quizResults       QuizResult[]
  conversations     Conversation[]
  learnings         Learning[]
  pushSubscriptions PushSubscription[]

  // Issue #64: Consolidated localStorage data
  accessibility     AccessibilitySettings?
  onboarding        OnboardingState?
  pomodoroStats     PomodoroStats?
  calendarEvents    CalendarEvent[]
  htmlSnippets      HtmlSnippet[]
  homeworkSessions  HomeworkSession[]
}

model Profile {
  id            String   @id @default(cuid())
  userId        String   @unique
  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  name          String?
  age           Int?
  schoolYear    Int?
  schoolLevel   String   @default("superiore")
  gradeLevel    String?
  learningGoals String   @default("[]")

  // Character preferences (coach and buddy selection)
  preferredCoach String?  // melissa, roberto, chiara, andrea, favij
  preferredBuddy String?  // mario, noemi, enea, bruno, sofia

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// SETTINGS
// ============================================================================

model Settings {
  id            String  @id @default(cuid())
  userId        String  @unique
  user          User    @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Appearance
  theme         String  @default("system")
  language      String  @default("it")
  accentColor   String  @default("blue")

  // Accessibility
  fontSize           String  @default("medium")
  highContrast       Boolean @default(false)
  dyslexiaFont       Boolean @default(false)
  reducedMotion      Boolean @default(false)
  voiceEnabled       Boolean @default(true)
  simplifiedLanguage Boolean @default(false)
  adhdMode           Boolean @default(false)

  // AI Provider
  provider      String  @default("azure")
  model         String  @default("gpt-4o")
  budgetLimit   Float   @default(50.0)
  totalSpent    Float   @default(0.0)

  // Parent Mode Consent (Issue #63)
  parentChatConsentAt DateTime?  // When parent consented to chat with professors

  // Parent Dashboard (Issue #64)
  parentDashboardLastViewed DateTime?  // When parent last viewed the dashboard

  // Azure Cost Configuration
  azureCostConfig String?  // JSON: {token_cost, audio_cost, etc.}

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// PROGRESS & GAMIFICATION
// ============================================================================

model Progress {
  id                String    @id @default(cuid())
  userId            String    @unique
  user              User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  xp                Int       @default(0)
  level             Int       @default(1)

  // Streak
  streakCurrent     Int       @default(0)
  streakLongest     Int       @default(0)
  lastStudyDate     DateTime?

  // Aggregates
  totalStudyMinutes Int       @default(0)
  questionsAsked    Int       @default(0)
  sessionsThisWeek  Int       @default(0)

  // Complex data as JSON
  achievements      String    @default("[]")
  masteries         String    @default("[]")

  createdAt         DateTime  @default(now())
  updatedAt         DateTime  @updatedAt
}

model StudySession {
  id          String    @id @default(cuid())
  userId      String
  user        User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId   String
  subject     String
  startedAt   DateTime  @default(now())
  endedAt     DateTime?
  duration    Int?
  xpEarned    Int       @default(0)
  questions   Int       @default(0)

  // Student self-evaluation (1-5 stars)
  studentRating    Int?
  studentFeedback  String?

  // AI Maestro evaluation (1-10 score)
  maestroScore     Int?
  maestroFeedback  String?
  strengths        String?   // JSON array
  areasToImprove   String?   // JSON array

  // Session context
  topics           String    @default("[]") // JSON array of topics covered
  conversationId   String?   // Link to Conversation

  // Tools created during session
  materials        Material[]

  @@index([userId])
  @@index([startedAt])
  @@index([conversationId])
}

// ============================================================================
// EDUCATION: FLASHCARDS & QUIZZES
// ============================================================================

model FlashcardProgress {
  id             String    @id @default(cuid())
  userId         String
  user           User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  cardId         String
  deckId         String?

  // FSRS Algorithm State
  difficulty     Float     @default(0.0)
  stability      Float     @default(0.0)
  retrievability Float     @default(1.0)
  state          String    @default("new")

  // Review tracking
  reps           Int       @default(0)
  lapses         Int       @default(0)
  lastReview     DateTime?
  nextReview     DateTime?

  createdAt      DateTime  @default(now())
  updatedAt      DateTime  @updatedAt

  @@unique([userId, cardId])
  @@index([userId])
  @@index([nextReview])
}

model QuizResult {
  id             String   @id @default(cuid())
  userId         String
  user           User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  quizId         String
  subject        String?
  score          Int
  totalQuestions Int
  percentage     Float

  // Detailed answers as JSON
  answers        String   @default("[]")

  completedAt    DateTime @default(now())

  @@index([userId])
  @@index([completedAt])
}

// ============================================================================
// CONVERSATIONS & MEMORY
// ============================================================================

model Conversation {
  id           String    @id @default(cuid())
  userId       String
  user         User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId    String
  title        String?

  // Summary system
  summary      String?
  keyFacts     String?
  topics       String    @default("[]")

  // Message management
  messageCount Int       @default(0)
  messages     Message[]

  // Status
  isActive     Boolean   @default(true)
  lastMessageAt DateTime?

  // Parent Mode (Issue #63)
  isParentMode Boolean   @default(false)
  studentId    String?   // The student being discussed (for parent conversations)

  createdAt    DateTime  @default(now())
  updatedAt    DateTime  @updatedAt

  @@index([userId])
  @@index([maestroId])
  @@index([updatedAt])
  @@index([isParentMode])
}

model Message {
  id             String       @id @default(cuid())
  conversationId String
  conversation   Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)

  role           String
  content        String

  // Optional metadata
  toolCalls      String?
  tokenCount     Int?

  createdAt      DateTime     @default(now())

  @@index([conversationId])
  @@index([createdAt])
}

// ============================================================================
// LEARNINGS (Cross-session insights)
// ============================================================================

model Learning {
  id          String   @id @default(cuid())
  userId      String
  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Context
  maestroId   String?
  subject     String?

  // The learning itself
  category    String
  insight     String

  // Confidence tracking
  confidence  Float    @default(0.5)
  occurrences Int      @default(1)

  // Timestamps
  createdAt   DateTime @default(now())
  lastSeen    DateTime @updatedAt

  @@index([userId])
  @@index([category])
  @@index([confidence])
}

// ============================================================================
// STUDENT INSIGHT PROFILES (Multi-Maestro Learning Insights for Parents)
// Related: Issue #31
// ============================================================================

model StudentInsightProfile {
  id           String    @id @default(cuid())
  userId       String    @unique
  studentName  String

  // Access control (GDPR)
  visibleTo    String    @default("parents") // parents | teachers | both

  // Consent tracking
  parentConsent   Boolean  @default(false)
  studentConsent  Boolean  @default(false)
  consentDate     DateTime?
  deletionRequested DateTime?

  // Synthesized profile data as JSON
  insights     String    @default("[]") // MaestroInsight[]
  strengths    String    @default("[]") // StrengthArea[]
  growthAreas  String    @default("[]") // GrowthArea[]
  learningStyle String   @default("{}") // LearningStyle
  strategies   String    @default("[]") // Strategy[]

  // Historical snapshots
  progressHistory String  @default("[]") // ProfileSnapshot[]

  // Metadata
  sessionCount  Int       @default(0)
  lastSessionId String?
  confidenceScore Float   @default(0.0)

  createdAt    DateTime  @default(now())
  updatedAt    DateTime  @updatedAt

  // Access log for GDPR audit
  accessLogs   ProfileAccessLog[]

  @@index([userId])
}

model ProfileAccessLog {
  id         String   @id @default(cuid())
  profileId  String
  profile    StudentInsightProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)

  userId     String
  action     String   // view | download | share | edit | delete_request
  details    String?
  ipAddress  String?
  userAgent  String?

  timestamp  DateTime @default(now())

  @@index([profileId])
  @@index([timestamp])
}

// ============================================================================
// NOTIFICATIONS (Server-side persistence for cross-device sync)
// ============================================================================

model Notification {
  id          String   @id @default(cuid())
  userId      String

  type        String   // achievement | streak | reminder | break | session_end | level_up | calendar | system | flashcard_due | scheduled_session | suggestion
  title       String
  message     String
  actionUrl   String?
  metadata    String?  // JSON for additional data

  // Scheduler-specific fields (Issue #27)
  priority     String?  // high | medium | low
  relatedId    String?  // Reference to flashcard deck, session, etc.
  melissaVoice String?  // Voice script for Melissa TTS

  read        Boolean  @default(false)
  dismissed   Boolean  @default(false)

  // Scheduling for future notifications
  scheduledFor DateTime?
  sentAt       DateTime?

  createdAt   DateTime @default(now())
  expiresAt   DateTime? // Auto-delete after expiry

  @@index([userId])
  @@index([read])
  @@index([createdAt])
  @@index([scheduledFor])
}

// ============================================================================
// TELEMETRY (Usage Analytics & Grafana Integration)
// ============================================================================

model TelemetryEvent {
  id          String   @id @default(cuid())
  eventId     String   @unique // Client-generated event ID for deduplication

  // Event data
  timestamp   DateTime
  category    String   // navigation | education | conversation | maestro | tools | accessibility | error | performance
  action      String   // Specific action (page_view, quiz_started, etc.)
  label       String?  // Additional context (page name, maestro ID, etc.)
  value       Float?   // Numeric value (duration, count, etc.)
  metadata    String?  // JSON for additional key-value pairs

  // Session & user tracking
  sessionId   String
  userId      String?  // Optional, only if authenticated

  createdAt   DateTime @default(now())

  @@index([userId])
  @@index([sessionId])
  @@index([timestamp])
  @@index([category])
  @@index([action])
}

// ============================================================================
// METHOD PROGRESS (Autonomy Tracking - Issue #28)
// ============================================================================

model MethodProgress {
  id        String @id @default(cuid())
  userId    String @unique

  // Skill progress (JSON stored)
  mindMaps       String @default("{}") // MindMapProgress JSON
  flashcards     String @default("{}") // FlashcardProgress JSON
  selfAssessment String @default("{}") // SelfAssessmentProgress JSON
  helpBehavior   String @default("{}") // HelpBehavior JSON
  methodTransfer String @default("{}") // MethodTransfer JSON

  // Events history (JSON array)
  events String @default("[]") // MethodEvent[] JSON

  // Computed scores
  autonomyScore Float @default(0) // 0-1

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
  @@index([autonomyScore])
}

// ============================================================================
// MATERIALS (Persisted tool outputs - T-20)
// ============================================================================

model Material {
  id          String   @id @default(cuid())
  userId      String
  toolId      String   @unique // Client-generated tool ID
  toolType    String   // mindmap, quiz, flashcard, demo, etc.
  title       String
  content     String   // JSON string

  // Context
  maestroId   String?
  sessionId   String?
  session     StudySession? @relation(fields: [sessionId], references: [id])
  subject     String?
  preview     String?  // Preview text for lists

  // Migrated from CreatedTool
  topic          String?
  conversationId String?

  // Status
  status      String   @default("active") // active, archived, deleted

  // User interaction (Issue #37 - Archive features)
  userRating   Int?     // 1-5 stars
  isBookmarked Boolean  @default(false)
  viewCount    Int      @default(0)

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([userId])
  @@index([toolType])
  @@index([status])
  @@index([sessionId])
  @@index([createdAt])
  @@index([isBookmarked])
}

// ============================================================================
// PARENT NOTES (Auto-generated session summaries for parents)
// ============================================================================

model ParentNote {
  id          String    @id @default(cuid())
  userId      String
  sessionId   String
  maestroId   String
  subject     String
  duration    Int       // minutes

  // Content
  summary     String    // Brief summary for parents
  highlights  String    // JSON array of achievements
  concerns    String?   // JSON array of concerns (can be empty)
  suggestions String?   // JSON array of suggestions

  // Timestamps
  generatedAt DateTime  @default(now())
  viewedAt    DateTime?

  @@index([userId])
  @@index([sessionId])
  @@index([generatedAt])
}

// ============================================================================
// CREATED TOOLS (Maestro-generated interactive tools - Issue #39, #37)
// DEPRECATED: Use Material table instead. Kept for migration buffer.
// ============================================================================

model CreatedTool {
  id             String   @id @default(cuid())
  userId         String

  // Tool metadata
  type           String   // mindmap, quiz, demo, flashcard, search, summary, diagram, timeline
  title          String
  topic          String?
  content        String   @default("{}") // JSON data

  // Context
  maestroId      String?
  conversationId String?
  sessionId      String?

  // User interaction
  userRating     Int?     // 1-5 stars
  isBookmarked   Boolean  @default(false)
  viewCount      Int      @default(0)

  // Timestamps
  createdAt      DateTime @default(now())
  updatedAt      DateTime @updatedAt

  @@index([userId])
  @@index([type])
  @@index([createdAt])
  @@index([isBookmarked])
}

// ============================================================================
// STUDY SCHEDULER (Smart Notifications & Scheduling - Issue #27)
// ============================================================================

model StudySchedule {
  id          String   @id @default(cuid())
  userId      String   @unique

  // Notification preferences (JSON)
  preferences String   @default("{}") // NotificationPreferences JSON

  sessions    ScheduledSession[]
  reminders   CustomReminder[]

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([userId])
}

model ScheduledSession {
  id            String   @id @default(cuid())
  userId        String
  scheduleId    String
  schedule      StudySchedule @relation(fields: [scheduleId], references: [id], onDelete: Cascade)

  // Session details
  dayOfWeek     Int      // 0-6 (Sunday-Saturday)
  time          String   // "16:00" format
  duration      Int      @default(30) // minutes
  subject       String
  maestroId     String?
  topic         String?

  // Scheduling options
  active        Boolean  @default(true)
  reminderOffset Int     @default(5) // minutes before notification
  repeat        String   @default("weekly") // daily | weekly | weekdays | none

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt

  @@index([userId])
  @@index([scheduleId])
  @@index([dayOfWeek])
  @@index([active])
}

model CustomReminder {
  id            String   @id @default(cuid())
  userId        String
  scheduleId    String
  schedule      StudySchedule @relation(fields: [scheduleId], references: [id], onDelete: Cascade)

  // Reminder details
  datetime      DateTime
  message       String
  subject       String?
  maestroId     String?

  // Scheduling options
  repeat        String   @default("none") // daily | weekly | none
  active        Boolean  @default(true)

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt

  @@index([userId])
  @@index([scheduleId])
  @@index([datetime])
  @@index([active])
}

// ============================================================================
// PWA PUSH NOTIFICATIONS (ADR-0014)
// Push subscription storage for background notifications
// ============================================================================

model PushSubscription {
  id        String    @id @default(cuid())
  userId    String
  endpoint  String    @unique // Push service endpoint URL
  p256dh    String    // Public key for encryption
  auth      String    // Auth secret for encryption
  userAgent String?   // Browser/device info for debugging
  createdAt DateTime  @default(now())
  expiresAt DateTime? // Optional expiration

  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  @@index([userId])
}

// ============================================================================
// ACCESSIBILITY SETTINGS (Issue #64 - localStorage consolidation)
// Migrated from: accessibility-store.ts
// ============================================================================

model AccessibilitySettings {
  id        String @id @default(cuid())
  userId    String @unique
  user      User   @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Dyslexia support
  dyslexiaFont        Boolean @default(false)
  extraLetterSpacing  Boolean @default(false)
  increasedLineHeight Boolean @default(false)

  // Visual support
  highContrast   Boolean @default(false)
  largeText      Boolean @default(false)
  reducedMotion  Boolean @default(false)

  // Text-to-Speech
  ttsEnabled  Boolean @default(false)
  ttsSpeed    Float   @default(1.0) // 0.5 to 2.0
  ttsAutoRead Boolean @default(false)

  // ADHD support
  adhdMode           Boolean @default(false)
  distractionFreeMode Boolean @default(false)
  breakReminders     Boolean @default(false)

  // General accessibility
  lineSpacing        Float   @default(1.0) // 1.0 to 2.0
  fontSize           Float   @default(1.0) // 0.8 to 1.5
  colorBlindMode     Boolean @default(false)
  keyboardNavigation Boolean @default(true)

  // Custom colors
  customBackgroundColor String @default("#ffffff")
  customTextColor       String @default("#000000")

  // ADHD Session Config (JSON)
  adhdConfig String @default("{}") // ADHDSessionConfig JSON
  adhdStats  String @default("{}") // ADHDSessionStats JSON

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
}

// ============================================================================
// ONBOARDING STATE (Issue #64 - localStorage consolidation)
// Migrated from: onboarding-store.ts
// ============================================================================

model OnboardingState {
  id        String @id @default(cuid())
  userId    String @unique
  user      User   @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Flow state
  hasCompletedOnboarding Boolean  @default(false)
  onboardingCompletedAt  DateTime?
  currentStep            String   @default("welcome") // OnboardingStep
  isReplayMode           Boolean  @default(false)
  isVoiceMuted           Boolean  @default(false)

  // Collected data (JSON)
  data String @default("{}") // OnboardingData JSON

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
}

// ============================================================================
// POMODORO STATS (Issue #64 - localStorage consolidation)
// Migrated from: pomodoro-store.ts
// ============================================================================

model PomodoroStats {
  id        String @id @default(cuid())
  userId    String @unique
  user      User   @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Persistent stats
  completedPomodoros Int @default(0)
  totalFocusTime     Int @default(0) // in seconds
  todayPomodoros     Int @default(0)
  todayFocusMinutes  Int @default(0)
  lastActiveDate     String @default("")

  // Settings (JSON)
  settings String @default("{}") // PomodoroSettings JSON

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
}

// ============================================================================
// CALENDAR EVENTS (Issue #64 - localStorage consolidation)
// Migrated from: calendar-store.ts
// ============================================================================

model CalendarEvent {
  id        String   @id @default(cuid())
  userId    String
  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  title       String
  description String?
  subject     String?
  maestroId   String?

  // Timing
  date        DateTime
  startTime   String?  // "16:00" format
  endTime     String?
  duration    Int?     // in minutes
  allDay      Boolean  @default(false)

  // Recurrence
  recurring   Boolean  @default(false)
  recurrence  String?  // daily | weekly | monthly | none

  // Status
  completed   Boolean  @default(false)
  reminded    Boolean  @default(false)

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([userId])
  @@index([date])
}

// ============================================================================
// HTML SNIPPETS (Issue #64 - localStorage consolidation)
// Migrated from: app-store.ts HTMLSnippetsStore
// ============================================================================

model HtmlSnippet {
  id        String   @id @default(cuid())
  userId    String
  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  snippetId String   @unique // Client-generated ID
  html      String
  css       String?
  js        String?
  title     String?
  subject   String?
  maestroId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
  @@index([snippetId])
}

// ============================================================================
// HOMEWORK SESSIONS (Issue #64 - localStorage consolidation)
// Migrated from: homework-help-view.tsx session storage
// ============================================================================

model HomeworkSession {
  id        String   @id @default(cuid())
  userId    String
  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Session data
  subject     String?
  topic       String?
  problemType String?
  status      String   @default("active") // active | completed | abandoned

  // Messages and steps (JSON arrays)
  messages String @default("[]")
  steps    String @default("[]")

  // Timing
  startedAt   DateTime @default(now())
  completedAt DateTime?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
  @@index([status])
}

